"use client"

import { Plus, Edit, Eye, EyeOff, MapPin, Map, RefreshCw, Upload } from "lucide-react"
import Link from "next/link"
import { useState, useEffect, useRef } from "react"
import { AdminFrame } from "@/components/dg/admin-frame"
import { authHeaders, request, resolveMediaURL, splitTags } from "@/components/dg/api"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"
import { toast } from "sonner"

type Spot = {
  id: number
  name: string
  name_en: string | null
  description: string | null
  description_en: string | null
  tags: string[]
  location: { lat: number; lng: number } | null
  visit_duration_min: number
  image_url: string | null
  sort_order: number
  is_active: boolean
}

type Route = {
  id: number
  name: string
  name_en: string | null
  description: string | null
  tags: string[]
  spot_ids: number[]
  sort_order: number
  is_active: boolean
}

function SpotList({ onSelect, spots }: { onSelect: (spot: Spot) => void, spots: Spot[] }) {
  console.log("SpotList rendering with spots:", spots)
  return (
    <div className="space-y-3">
      {spots.map((spot) => {
        const resolvedImage = spot.image_url ? resolveMediaURL(spot.image_url) : null
        console.log(`Spot ${spot.id} image_url:`, spot.image_url, "resolved:", resolvedImage)
        return (
          <Card key={spot.id} className="p-4 cursor-pointer hover:shadow-md transition-shadow" onClick={() => onSelect(spot)}>
            <div className="flex items-start justify-between gap-4">
              <div className="flex items-start gap-4 flex-1 min-w-0">
                {resolvedImage ? (
                  <img
                    className="h-16 w-24 rounded-lg object-cover flex-shrink-0"
                    src={resolvedImage}
                    alt={spot.name}
                    onError={(e) => {
                      console.error(`Failed to load image for spot ${spot.id}:`, resolvedImage)
                      ;(e.target as HTMLImageElement).style.display = "none"
                    }}
                    onLoad={() => {
                      console.log(`Successfully loaded image for spot ${spot.id}:`, resolvedImage)
                    }}
                  />
                ) : (
                  <div className="grid h-16 w-24 flex-shrink-0 place-items-center rounded-lg bg-muted text-xs text-muted-foreground">
                    暂无图
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-medium truncate">{spot.name}</h3>
                    {spot.name_en ? <span className="text-xs text-muted-foreground truncate">({spot.name_en})</span> : null}
                  </div>
                  {spot.description ? <p className="text-sm text-muted-foreground line-clamp-2 mb-2">{spot.description}</p> : null}
                  {spot.tags?.length ? (
                    <div className="flex flex-wrap gap-1">
                      {spot.tags.map((tag) => (
                        <span key={tag} className="px-2 py-0.5 bg-primary/10 text-primary text-xs rounded-full">
                          {tag}
                        </span>
                      ))}
                    </div>
                  ) : null}
                </div>
              </div>
              <div className="flex items-center gap-2 flex-shrink-0">
                <span className={`px-2 py-1 rounded-full text-xs ${spot.is_active ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-500"}`}>
                  {spot.is_active ? <><Eye className="h-3 w-3 inline mr-1" /> 上线</> : <><EyeOff className="h-3 w-3 inline mr-1" /> 下线</>}
                </span>
                <Button size="sm" variant="ghost"><Edit className="h-4 w-4" /></Button>
              </div>
            </div>
          </Card>
        )
      })}
    </div>
  )
}

function SpotEditor({ spot: initial, onSaved }: { spot: Spot | null, onSaved?: () => void }) {
  const [spot, setSpot] = useState(initial || { name: "", name_en: null, description: null, description_en: null, tags: [], location: null, visit_duration_min: 30, image_url: null, sort_order: 0, is_active: true })
  const [saving, setSaving] = useState(false)
  const [tagInput, setTagInput] = useState("")
  const [imagePreview, setImagePreview] = useState<string | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (initial) {
      console.log("Initial spot loaded:", initial)
      setSpot(initial)
      if (initial.image_url) {
        const resolved = resolveMediaURL(initial.image_url)
        console.log("Setting initial preview URL:", resolved)
        setImagePreview(resolved)
      } else {
        setImagePreview(null)
      }
    } else {
      setSpot({ name: "", name_en: null, description: null, description_en: null, tags: [], location: null, visit_duration_min: 30, image_url: null, sort_order: 0, is_active: true })
      setImagePreview(null)
    }
  }, [initial])

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      console.log("File selected:", file.name, file.type, file.size)
      const reader = new FileReader()
      reader.onload = (event) => {
        const dataUrl = event.target?.result as string
        console.log("Local preview dataURL created")
        setImagePreview(dataUrl)
      }
      reader.readAsDataURL(file)
    }
  }

  const saveSpot = async () => {
    setSaving(true)
    try {
      console.log("Saving spot with payload:", { name: spot.name, image_url: spot.image_url })
      const payload = {
        name: spot.name,
        name_en: spot.name_en,
        description: spot.description,
        description_en: spot.description_en,
        tags: spot.tags,
        location: spot.location,
        visit_duration_min: spot.visit_duration_min,
        sort_order: spot.sort_order,
        is_active: spot.is_active
      }

      let savedSpot: Spot
      if (initial) {
        savedSpot = await request(`/api/admin/spots/${initial.id}`, {
          method: "PUT",
          headers: authHeaders({ "Content-Type": "application/json" }),
          body: JSON.stringify(payload)
        })
      } else {
        savedSpot = await request("/api/admin/spots", {
          method: "POST",
          headers: authHeaders({ "Content-Type": "application/json" }),
          body: JSON.stringify(payload)
        })
      }
      console.log("Spot saved successfully:", savedSpot)

      const file = fileInputRef.current?.files?.[0]
      if (file && savedSpot?.id) {
        console.log("Uploading image for spot:", savedSpot.id)
        const form = new FormData()
        form.append("file", file)
        const imageRes = await request(`/api/admin/spots/${savedSpot.id}/image`, {
          method: "POST",
          headers: authHeaders(),
          body: form
        })
        console.log("Image upload response:", imageRes)
        const newResolvedUrl = resolveMediaURL(imageRes.image_url)
        console.log("Resolved new image URL:", newResolvedUrl)
        setSpot((s) => ({ ...s, image_url: imageRes.image_url }))
        setImagePreview(newResolvedUrl)
      }

      toast.success(initial ? "景点已更新" : "景点已新增")
      if (onSaved) onSaved()
    } catch (err: any) {
      console.error("Save failed:", err)
      toast.error(err?.message || "保存失败")
    } finally {
      setSaving(false)
    }
  }

  console.log("SpotEditor current imagePreview:", imagePreview)
  return (
    <div className="space-y-6">
      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-4">
          <div>
            <Label>景点名称 <span className="text-red-500">*</span></Label>
            <Input value={spot.name} onChange={(e) => setSpot((s) => ({ ...s, name: e.target.value }))} placeholder="例如：灵山大佛" />
          </div>
          <div>
            <Label>英文名称</Label>
            <Input value={spot.name_en || ""} onChange={(e) => setSpot((s) => ({ ...s, name_en: e.target.value || null }))} placeholder="例如：Lingshan Giant Buddha" />
          </div>
          <div>
            <Label>标签 <span className="text-muted-foreground text-xs">（用逗号分隔，按回车添加）</span></Label>
            <Input
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              placeholder="例如：历史,文化,拍照"
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault()
                  const newTags = Array.from(new Set([...spot.tags, ...splitTags(tagInput)]))
                  setSpot((s) => ({ ...s, tags: newTags }))
                  setTagInput("")
                }
              }}
            />
            <div className="mt-2 flex flex-wrap gap-2">
              {spot.tags.map((tag) => (
                <span key={tag} className="px-2 py-1 bg-primary/10 text-primary text-sm rounded-full flex items-center gap-1">
                  {tag}
                  <button onClick={() => {
                    setSpot((s) => ({ ...s, tags: s.tags.filter((t) => t !== tag) }))
                  }} className="hover:text-red-500">
                    ×
                  </button>
                </span>
              ))}
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>游览时长（分钟）</Label>
              <Input type="number" value={spot.visit_duration_min} onChange={(e) => setSpot((s) => ({ ...s, visit_duration_min: Number(e.target.value) }))} />
            </div>
            <div>
              <Label>排序</Label>
              <Input type="number" value={spot.sort_order} onChange={(e) => setSpot((s) => ({ ...s, sort_order: Number(e.target.value) }))} />
            </div>
          </div>
          <div className="flex items-center justify-between">
            <Label>状态</Label>
            <Switch checked={spot.is_active} onCheckedChange={(v) => setSpot((s) => ({ ...s, is_active: v }))} />
          </div>
        </div>
        <div className="space-y-4">
          <div>
            <Label>景点图片</Label>
            <div className="mt-2 border border-border rounded-lg p-4">
              {imagePreview ? (
                <img
                  src={imagePreview}
                  alt="预览"
                  className="w-full h-48 object-cover rounded-lg mb-3"
                  onError={(e) => {
                    console.error("Failed to load preview image:", imagePreview)
                  }}
                  onLoad={() => {
                    console.log("Preview image loaded successfully:", imagePreview)
                  }}
                />
              ) : (
                <div className="h-48 flex items-center justify-center bg-muted/30 rounded-lg mb-3">
                  <p className="text-muted-foreground text-sm">暂无图片预览</p>
                </div>
              )}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleFileChange}
                className="hidden"
                id="spot-image"
              />
              <Button
                variant="outline"
                className="w-full"
                onClick={() => fileInputRef.current?.click()}
              >
                <Upload className="h-4 w-4 mr-2" />
                {initial?.image_url ? "更换图片" : "选择图片"}
              </Button>
              <p className="text-xs text-muted-foreground mt-2 text-center">
                支持 jpg/png/gif/webp，最大 10MB
              </p>
            </div>
          </div>
          <div>
            <Label>景点简介</Label>
            <Textarea value={spot.description || ""} onChange={(e) => setSpot((s) => ({ ...s, description: e.target.value || null }))} placeholder="介绍这个景点" rows={4} />
          </div>
          <div>
            <Label>英文简介</Label>
            <Textarea value={spot.description_en || ""} onChange={(e) => setSpot((s) => ({ ...s, description_en: e.target.value || null }))} placeholder="Introduction to this spot" rows={3} />
          </div>
        </div>
      </div>
      <div className="flex justify-end gap-3 pt-4 border-t">
        <Button
          variant="outline"
          onClick={() => {
            if (initial) {
              setSpot(initial)
              if (initial.image_url) {
                setImagePreview(resolveMediaURL(initial.image_url))
              } else {
                setImagePreview(null)
              }
            } else {
              setSpot({ name: "", name_en: null, description: null, description_en: null, tags: [], location: null, visit_duration_min: 30, image_url: null, sort_order: 0, is_active: true })
              setImagePreview(null)
            }
            if (fileInputRef.current) {
              fileInputRef.current.value = ""
            }
          }}
        >
          重置
        </Button>
        <Button onClick={saveSpot} disabled={saving || !spot.name}>
          {saving ? "保存中..." : "保存"}
        </Button>
      </div>
    </div>
  )
}

function RouteList({ routes }: { routes: Route[] }) {
  return (
    <div className="space-y-3">
      {routes.map((route) => (
        <Card key={route.id} className="p-4">
          <div className="flex items-start justify-between gap-4">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 mb-1">
                <h3 className="font-medium truncate">{route.name}</h3>
                {route.name_en ? <span className="text-xs text-muted-foreground truncate">({route.name_en})</span> : null}
              </div>
              {route.description ? <p className="text-sm text-muted-foreground line-clamp-2 mb-2">{route.description}</p> : null}
              {route.tags?.length ? (
                <div className="flex flex-wrap gap-1">
                  {route.tags.map((tag) => (
                    <span key={tag} className="px-2 py-0.5 bg-primary/10 text-primary text-xs rounded-full">
                      {tag}
                    </span>
                  ))}
                </div>
              ) : null}
            </div>
            <div className="flex items-center gap-2 flex-shrink-0">
              <span className={`px-2 py-1 rounded-full text-xs ${route.is_active ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-500"}`}>
                {route.is_active ? "上线" : "下线"}
              </span>
            </div>
          </div>
        </Card>
      ))}
    </div>
  )
}

export function ScenicContent() {
  const [selected, setSelected] = useState<Spot | null>(null)
  const [spots, setSpots] = useState<Spot[]>([])
  const [routes, setRoutes] = useState<Route[]>([])
  const [loading, setLoading] = useState(true)

  const loadData = async () => {
    setLoading(true)
    try {
      console.log("Loading scenic data...")
      const [spotsData, routesData] = await Promise.all([
        request("/api/admin/spots", { headers: authHeaders() }),
        request("/api/admin/routes", { headers: authHeaders() }),
      ])
      console.log("Spots data received:", spotsData)
      console.log("Routes data received:", routesData)
      setSpots(spotsData)
      setRoutes(routesData)
    } catch (err: any) {
      console.error("Load failed:", err)
      toast.error(err?.message || "加载失败")
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadData()
  }, [])

  return (
    <AdminFrame
      title="景区管理"
      description="管理景点和游览路线数据"
      actions={
        <div className="flex gap-2">
          <Button asChild><Link href="#"><Map className="h-4 w-4" /> 管理路线</Link></Button>
          <Button onClick={() => setSelected(null)}><Plus className="h-4 w-4" /> 新增景点</Button>
          <Button onClick={loadData} disabled={loading}><RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} /> 刷新</Button>
        </div>
      }
    >
      {loading ? (
        <div className="grid place-items-center p-8">
          <p className="text-muted-foreground">加载中...</p>
        </div>
      ) : (
        <div className="grid gap-6 lg:grid-cols-[1fr_1fr]">
          <div>
            <Tabs defaultValue="spots">
              <TabsList className="mb-4">
                <TabsTrigger value="spots"><MapPin className="h-4 w-4 mr-2" /> 景点列表</TabsTrigger>
                <TabsTrigger value="routes"><Map className="h-4 w-4 mr-2" /> 路线列表</TabsTrigger>
              </TabsList>
              <TabsContent value="spots">
                <SpotList onSelect={setSelected} spots={spots} />
              </TabsContent>
              <TabsContent value="routes">
                <RouteList routes={routes} />
              </TabsContent>
            </Tabs>
          </div>
          <div>
            <Card className="p-6">
              <div className="mb-6 flex items-center justify-between">
                <h2 className="text-lg font-semibold">{selected ? "编辑景点" : "新增景点"}</h2>
              </div>
              <SpotEditor spot={selected} onSaved={loadData} />
            </Card>
          </div>
        </div>
      )}
    </AdminFrame>
  )
}
